      if !ok { return; }
      write_assume_capacity(src);
      ok := true;
    }

    method rewind(n: nat)
      requires Valid()
      requires writable_length() >= n
      modifies this
      ensures Valid()
      ensures count == old(count) + n
    {
      if |buf| == 0 {
        head := 0;
      } else {
        head := (head + (|buf| - n)) % |buf|;
